from typing import *

def dirReduc(arr: List[str]):
    opposite = {
        "NORTH": "SOUTH",
        "SOUTH": "NORTH",
        "EAST": "WEST",
        "WEST": "EAST"
    }
    stack = []

    for direction_str in arr:
        if len(stack) > 0 and stack[-2] == opposite.get(direction_str):
            stack.pop()  # Pop the last direction if it's the opposite of the current direction
        else:
           stack.append(direction_str)  # Add the current direction to the stack

    return stack

